import React, { Component } from "react"
import { Link } from "gatsby"
import {FaFacebook, FaGithub, FaLinkedin} from "react-icons/fa"


class Navbar extends Component  {

    constructor(props) {
        super(props);
        this.state = {}
        this.closeRef = React.createRef();
    };

  

    render() {

        return(
                <nav className="navbar">
                    {/* <div className="navbar__infowidth"> */}
                        <div className="navbar__logo">
                            <h2>Tiago Murer</h2>
                        </div>

                        <div className="navbar__info desktop">
                            <Link to="/"><span>Quem sou eu</span> </Link>
                            <Link to="/"><span>Projetos</span> </Link>
                            <Link to="/"> <span>Contato</span> </Link>
                        </div>

                        <div className="navbar__links desktop">
                            <a target="_blank" rel="noopener noreferrer" href="https://www.facebook.com/tiagomurer"><FaFacebook  className="navbar__links__icon"/></a>
                            <a target="_blank" rel="noopener noreferrer" href="https://www.linkedin.com/in/tiagomurer"><FaGithub className="navbar__links__icon"/> </a>
                            <a target="_blank" rel="noopener noreferrer" href="https://github.com/tsmurer"><FaLinkedin className="navbar__links__icon"/></a>
                        </div>
                    {/* </div> */}
                </nav>
        )
    }
}

export default Navbar